async (params, browser) => {
  // Open the tweet
  await browser.open(`${params.tweet_url}`)

  // Wait for page content
  await browser.waitForSelector('article[data-testid=\'tweet\']', 15000)

  // Let page settle
  await browser.wait(1000)

  // Wait for retweet button
  await browser.waitForSelector('[data-testid$=\'retweet\']', 10000)

  // Click retweet
  await browser.click('[data-testid$=\'retweet\']')

  // Wait for retweet menu
  await browser.waitForSelector('[data-testid=\'retweetConfirm\'], [data-testid=\'repostConfirm\']', 5000)

  // Confirm retweet
  await browser.click('[data-testid=\'retweetConfirm\'], [data-testid=\'repostConfirm\']')

  await browser.wait(1500)

  const result = await browser.evaluate(`return { success: true, message: 'Retweeted successfully' }`)

  return result
}
